import { SeedApiClient } from "../../../src/Client";
import { mockServerPool } from "../../mock-server/MockServerPool";

describe("AuthClient", () => {
    test("getToken", async () => {
        const server = mockServerPool.createServer();
        const client = new SeedApiClient({
            maxRetries: 0,
            token: "test",
            apiVersion: "test",
            apiKey: "test",
            environment: { base: server.baseUrl, auth: server.baseUrl, upload: server.baseUrl },
        });
        const rawRequestBody = {
            client_id: "client_id",
            client_secret: "client_secret",
            audience: "https://api.example.com",
            grant_type: "client_credentials",
        };
        const rawResponseBody = { access_token: "access_token", expires_in: 1, refresh_token: "refresh_token" };

        server
            .mockEndpoint()
            .post("/token")
            .jsonBody(rawRequestBody)
            .respondWith()
            .statusCode(200)
            .jsonBody(rawResponseBody)
            .build();

        const response = await client.anyAuth.auth.getToken({
            clientId: "client_id",
            clientSecret: "client_secret",
            audience: "https://api.example.com",
            grantType: "client_credentials",
        });
        expect(response).toEqual({
            body: {
                accessToken: "access_token",
                expiresIn: 1,
                refreshToken: "refresh_token",
            },
            ok: true,
            headers: expect.any(Object),
            rawResponse: expect.any(Object),
        });
    });
});
